#pragma once

#include "FF_Primitives.hpp"
#include <atomic>
#include <stdexcept>
#include <string_view>

namespace FastFHIR {

class Node; // Forward declaration — full definition in FF_Parser.hpp
class Builder;

// =====================================================================
// TYPE TRAITS (Auto-generated by ffc.py)
// =====================================================================
/**
 * @brief Maps C++ structs to their generated FastFHIR size and store functions.
 */
template<typename T> struct TypeTraits;

// =====================================================================
// PROXIES & HANDLES
// =====================================================================

struct PointerRef {
    Offset object_offset = FF_NULL_OFFSET;
    size_t field_vtable_offset = 0;
};

/**
 * @brief Ephemeral proxy object returned by ObjectHandle::operator[].
 * Allows assigning either an existing Offset or dynamically appending new data.
 */
class PointerPatchProxy {
    Builder* m_builder;
    PointerRef m_ref;

public:
    PointerPatchProxy(Builder* builder, PointerRef ref) : m_builder(builder), m_ref(ref) {}

    // Option A: Assign an existing offset
    PointerPatchProxy& operator=(Offset new_target_offset);

    // Option B: Concurrently append NEW data and patch the pointer simultaneously
    template <typename T_Data>
    Offset operator=(const T_Data& data);
};

/**
 * @brief Thread-local handle representing a specific parent object being built.
 * Replaces the unsafe global operator[] on the Builder itself.
 */
class ObjectHandle {
    Builder* m_builder;
    Offset   m_offset;
    uint16_t m_recovery;

public:
    ObjectHandle(Builder* builder, Offset offset, uint16_t recovery = 0) 
        : m_builder(builder), m_offset(offset), m_recovery(recovery) {}

    Offset offset() const { return m_offset; }
    uint16_t recovery() const { return m_recovery; }

    PointerPatchProxy operator[](FF_FieldKey key) const;
    PointerPatchProxy operator[](std::string_view key_name) const;
};


// =====================================================================
// BUILDER
// =====================================================================

class Builder {
    BYTE* m_base;
    size_t              m_capacity;
    std::atomic<Offset> m_stream_head;
    Offset              m_root_offset;
    uint16_t            m_root_recovery;
    uint32_t            m_version;
    std::atomic<bool>   m_finalizing;
    std::atomic<uint64_t> m_active_mutators;

    bool try_begin_mutation();
    void end_mutation();

public:
    Builder(const Builder&) = delete;
    Builder& operator=(const Builder&) = delete;
    Builder(Builder&&) = delete;
    Builder& operator=(Builder&&) = delete;

    /**
     * @brief Reserves a massive Virtual Address Space without consuming physical RAM.
     */
    Builder(size_t virtual_capacity = 2ULL * 1024 * 1024 * 1024, uint32_t version = FHIR_VERSION_R5);
    ~Builder();

    // --- Core Stream Access ---
    
    const BYTE* data() const { return m_base; }
    Size total_written() const { return m_stream_head.load(std::memory_order_relaxed); }

    // --- Lock-Free Concurrent Appending ---

    /**
     * @brief The core concurrent ingestion method. Cleaned up to use TypeTraits.
     */
    template<typename T_Data>
    Offset append(const T_Data& data) {
        if (!try_begin_mutation()) {
            throw std::runtime_error("FastFHIR: Builder is finalizing; append is no longer allowed.");
        }

        struct MutationGuard {
            Builder* self;
            ~MutationGuard() { self->end_mutation(); }
        } guard{this};

        // Automatically resolved via ffc.py generated traits
        Size exact_size = TypeTraits<T_Data>::size(data);
        
        Offset start = m_stream_head.fetch_add(exact_size, std::memory_order_relaxed);
        
        if (start + exact_size > m_capacity) {
            throw std::runtime_error("FastFHIR: Exceeded maximum virtual arena capacity.");
        }
        
        TypeTraits<T_Data>::store(m_base, start, data);
        
        return start;
    }

    /**
     * @brief Appends data to the stream and returns a thread-safe handle for [] assignments.
     */
    template<typename T_Data>
    ObjectHandle append_obj(const T_Data& data) {
        return ObjectHandle(this, append(data), TypeTraits<T_Data>::recovery);
    }

    /**
     * @brief Instantiates a read-only Node directly from a known offset mid-stream.
     */
    Node view_node(Offset offset, uint16_t recovery, FF_FieldKind kind = FF_FIELD_BLOCK) const;

    /**
     * @brief Low-level mutable access to a V-Table pointer for amending data.
     */
    void amend_pointer(Offset object_offset, size_t field_vtable_offset, Offset new_target_offset);

    // --- Finalization & Checksums ---

    /** 
     * @brief Sets the root resource pointer and recovery tag in the header. 
     * [NOTE] This function must be called before finalize().
     */
    void set_root(const ObjectHandle& handle);
    
    
    using HashCallback = std::function<std::vector<BYTE>(const unsigned char* byte_start, Size bytes_to_hash)>;
    /**
     * @brief Bakes the File Header, and executes the provided hashing callback to seal the file.
     * @param algo The cryptographic algorithm tag to write into the metadata.
     * @param hasher A callback that takes the payload and returns the raw hash bytes.
     * @return A view of the complete, sealed file (including the checksum footer) ready for network transmission.
     */
    std::string_view finalize(FF_Checksum_Algorithm algo = FF_CHECKSUM_NONE, const HashCallback& hasher = nullptr);
};

// =====================================================================
// INLINE TEMPLATE IMPLEMENTATIONS
// =====================================================================

inline PointerPatchProxy& PointerPatchProxy::operator=(Offset new_target_offset) {
    m_builder->amend_pointer(m_ref.object_offset, m_ref.field_vtable_offset, new_target_offset);
    return *this;
}

template <typename T_Data>
Offset PointerPatchProxy::operator=(const T_Data& data) {
    // 1. Thread-safe append of the child data
    Offset child_offset = m_builder->append(data);
    
    // 2. Thread-safe pointer patch on the parent V-Table
    m_builder->amend_pointer(m_ref.object_offset, m_ref.field_vtable_offset, child_offset);
    
    return child_offset;
}

inline PointerPatchProxy ObjectHandle::operator[](FF_FieldKey key) const {
    // Assuming FF_FieldKey generated by ffc.py contains the direct field offset
    return PointerPatchProxy(m_builder, PointerRef{m_offset, key.field_offset}); 
}

} // namespace FastFHIR